  ), [showExportMenu, t]);

  useHeader(t('reports_title'), t('reports_subtitle'), HeaderActions);

  useEffect(() => {
    const fetchData = async () => {
      setLoading(true);
      try {
        const [b, a, p, t_data] = await Promise.all([
            api.getBills(), 
            api.getAppointments(), 
            api.getPatients(), 
            api.getTransactions()
